// Handle voicemail: increment attempts, schedule retry if < 3 attempts
const SUPABASE_URL = 'https://wjukfdziomnejtlmegvv.supabase.co';
const SUPABASE_ANON_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6IndqdWtmZHppb21uZWp0bG1lZ3Z2Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzM1Mjk1ODIsImV4cCI6MjA4OTEwNTU4Mn0.12Vszqd1Lhp0M6FIB_pSF1l7T_SscB0X4AxwFTRrTVU';

const leadEmail = $json.lead_email;

// First, fetch current call_attempts
let currentAttempts = 0;
try {
  const getResp = await fetch(
    `${SUPABASE_URL}/rest/v1/cold_email_leads?email=eq.${encodeURIComponent(leadEmail)}&select=call_attempts`,
    {
      headers: {
        'apikey': SUPABASE_ANON_KEY,
        'Authorization': `Bearer ${SUPABASE_ANON_KEY}`
      }
    }
  );
  const rows = await getResp.json();
  if (rows && rows[0]) {
    currentAttempts = rows[0].call_attempts || 0;
  }
} catch (e) {
  // Default to 0
}

const newAttempts = currentAttempts + 1;
const maxRetries = 3;

let updateBody = {
  call_status: 'voicemail',
  call_attempts: newAttempts
};

if (newAttempts < maxRetries) {
  // Schedule retry in 2 days
  const retryDate = new Date();
  retryDate.setDate(retryDate.getDate() + 2);
  updateBody.next_call_date = retryDate.toISOString().split('T')[0];
  updateBody.call_status = 'voicemail_retry_scheduled';
} else {
  updateBody.call_status = 'voicemail_max_attempts';
}

try {
  await fetch(
    `${SUPABASE_URL}/rest/v1/cold_email_leads?email=eq.${encodeURIComponent(leadEmail)}`,
    {
      method: 'PATCH',
      headers: {
        'apikey': SUPABASE_ANON_KEY,
        'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: JSON.stringify(updateBody)
    }
  );
} catch (e) {
  // Log error but don't fail
}

return [{
  json: {
    ...updateBody,
    lead_email: leadEmail,
    business_name: $json.business_name,
    first_name: $json.first_name,
    retry_scheduled: newAttempts < maxRetries
  }
}];

// Log outreach timing data and decide whether to proceed with calls today
const timingData = $input.first().json;

// If the query failed or returned nothing, proceed anyway (no data yet)
if (!timingData || timingData.error || (Array.isArray(timingData) && timingData.length === 0)) {
  return [{ json: { _timing_data: [], _skip_today: false, _reason: 'No timing data available yet - proceeding with calls' } }];
}

const rows = Array.isArray(timingData) ? timingData : [timingData];
const today = new Date().getDay(); // 0=Sun, 1=Mon, ..., 6=Sat
const currentHour = new Date().getHours();

// Check if today's day_of_week appears in timing data with very low success
const todayRows = rows.filter(r => r.day_of_week === today);
let skipToday = false;
let skipReason = '';

if (todayRows.length > 0) {
  // If all rows for today show 0% positive outcome rate and we have enough data (10+ attempts)
  const totalAttempts = todayRows.reduce((sum, r) => sum + (r.total_attempts || 0), 0);
  const totalPositive = todayRows.reduce((sum, r) => sum + (r.positive_outcomes || 0), 0);
  if (totalAttempts >= 10 && totalPositive === 0) {
    skipToday = true;
    skipReason = `Day ${today} has 0% connect rate over ${totalAttempts} attempts - skipping`;
  }
}

return [{ json: { _timing_data: rows, _skip_today: skipToday, _reason: skipReason || 'Timing data logged - proceeding with calls' } }];
